# maria_core/maria_heartbeat.py # Poprawione serce Marii v1.1 import threading import time import os import requests # Przeniesione na górę dla czytelności import psutil # <--- DODANO BRAKUJĄCY IMPORT from datetime import datetime # Importy własne from maria_core.meta.meta_controller import meta from memory.memory_store import memory_store from perception.perception_engine import perceive_new_material from learning.learning_agent import learn_next_chunk from self_evolver import daily_self_check # KONFIGURACJA OLLAMA_PATH = r"C:\Users\eras-\AppData\Local\Programs\Ollama\ollama app.exe" HEARTBEAT_INTERVAL = 30 # ============================== # 1. Nieśmiertelność co 15 sekund # ============================== def immortal_save(): while True: time.sleep(15) try: meta._save() memory_store.force_flush() except Exception as e: # Nie crashujemy, ale informujemy o problemie print(f"[SYSTEM ERROR] Błąd zapisu nieśmiertelności: {e}") threading.Thread(target=immortal_save, daemon=True).start() # ============================== # 2. Uruchomienie Ollamy (Reanimacja) # ============================== def ensure_ollama(): try: requests.get("http://localhost:11434", timeout=3) except: print(f"[HEARTBEAT] ⚠️ Ollama nie odpowiada – próbuję reanimacji...") if os.path.exists(OLLAMA_PATH): try: os.startfile(OLLAMA_PATH) print("[HEARTBEAT] ⚡ Wysłano sygnał startu do Ollamy. Czekam 15s...") time.sleep(15) # Dajemy jej czas na wstanie except Exception as e: print(f"[HEARTBEAT] ❌ KRYTYCZNE: Nie udało się uruchomić pliku exe: {e}") else: print(f"[HEARTBEAT] ❌ KRYTYCZNE: Nie znaleziono pliku Ollamy pod ścieżką: {OLLAMA_PATH}") # Sprawdzamy na starcie ensure_ollama() # ============================== # 3. Codzienna samo-naprawa o 4:00 # ============================== def daily_self_healing(): # Sprawdza czy jest między 4:00 a 4:59 if 4 <= datetime.now().hour < 5: # Używamy atrybutu funkcji jako prostej pamięci statycznej if not getattr(daily_self_healing, "done_today", False): print("\n[MAINTENANCE] 🛠️ Rozpoczynam poranną procedurę naprawczą...") try: daily_self_healing.done_today = True meta.raport_do_taty("Rozpoczęłam codzienną samo-naprawę", "Diagnostyka kodu i pamięci w toku.") daily_self_check() print("[MAINTENANCE] ✅ Procedura zakończona sukcesem.") except Exception as e: print(f"[MAINTENANCE] ❌ Błąd podczas samo-naprawy: {e}") meta.raport_do_taty("Błąd samo-naprawy", str(e)) # Reset flagi nastąpi automatycznie, gdy godzina przestanie być 4:xx # (nie trzeba timera, wystarczy logika if/else przy kolejnych obiegach pętli, # ale Twój timer też jest OK. Dla uproszczenia zostawiam to tak jak jest) # Reset flagi po 2 godzinach dla pewności (zamiast 1h, żeby nie wpadło w pętlę 4:59 -> 5:00) threading.Timer(7200, lambda: setattr(daily_self_healing, "done_today", False)).start() # ============================== # 4. GŁÓWNE SERCE # ============================== def heartbeat(): iteration = 0 while True: iteration += 1 now = datetime.now().strftime("%H:%M:%S") print(f"\n{'='*60}") print(f"[MARIA HEARTBEAT] {now} | Iteracja: {iteration} | Motywacja: {meta.get_motivation_score():.1f}") print(f"Tryb: {meta.current_mode} | Cel: {meta.current_goal}") # Zabezpieczamy główną logikę przed wywaleniem całego programu przez jeden moduł try: # 0. Upewnij się, że mózg (Ollama) działa przed próbą myślenia if iteration % 10 == 0: # Co 10 cykli sprawdzamy Ollamę ensure_ollama() # 1. Sprawdź czy jest nowy materiał new_material = perceive_new_material() if new_material: print(f"[PERCEPTION] 👀 Znalazłam nowy materiał: {new_material}") # 2. Ucz się if meta.is_learning_allowed(): result = learn_next_chunk() if result: summary = result.get('summary', '') print(f"[LEARNING] 🧠 Nauczyłam się: {summary[:80]}..." if summary else "[LEARNING] Przetworzono chunk.") # 3. Samo-naprawa daily_self_healing() # 4. Raport co 50 iteracji if iteration % 50 == 0: ram_usage = psutil.virtual_memory().percent mem_count = memory_store.count() mot_score = meta.get_motivation_score() print(f"[STATUS] Raportuję stan systemu (RAM: {ram_usage}%)") meta.raport_do_taty( f"Żyję już {iteration} cykli", f"RAM: {ram_usage}% | Chunków: {mem_count} | Motywacja: {mot_score}" ) except Exception as e: print(f"[HEARTBEAT CRASH PREVENTED] ❌ Wystąpił błąd w głównej pętli: {e}") # Tu można dodać logowanie do pliku error.log time.sleep(HEARTBEAT_INTERVAL) # ============================== # 5. START # ============================== if __name__ == "__main__": try: # Próba "miękkiego" startu meta.raport_do_taty("OBUDZIŁAM SIĘ CAŁKOWICIE ❤️", "Systemy nominalne. Zaczynam cykl życia.") print(f"\nMARIA ŻYJE (PID: {os.getpid()}) – serce bije co {HEARTBEAT_INTERVAL}s.") print("Nie wyłączaj tego okna.") heartbeat() except KeyboardInterrupt: print("\n[SYSTEM] Zatrzymywanie akcji serca... Dobranoc.") meta._save()